date_format(JF.RKRQ, '%Y') as nd,
COUNT(JF.DJXH) as bs,
SUM(
timestampdiff(
MONTH,
jf.SKSSQQ,
jf.SKSSQZ
) + 1
) as hs,
SUM(JF.YBTSE) as ybtse,
SUM(JF.JCGHJE) as jcghje,
